\"],\"kbVersion\":2} -->\n<!-- wp:kadence/column {\"borderWidth\":[\"\",\"\",\"\",\"\"],\"uniqueID\":\"73_f15d7c-2c\",\"kbVersion\":2} -->\n<div class=\"wp-block-kadence-column kadence-column73_f15d7c-2c\"><div class=\"kt-inside-inner-col\"><!-- wp:kadence/advancedheading {\"uniqueID\":\"73_2bc723-2d\",\"color\":\"palette9\",\"markBorder\":\"\",\"markBorderStyles\":[{\"top\":[null,\"\",\"\"],\"right\":[null,\"\",\"\"],\"bottom\":[null,\"\",\"\"],\"left\":[null,\"\",\"\"],\"unit\":\"px\"}],\"tabletMarkBorderStyles\":[{\"top\":[null,\"\",\"\"],\"right\":[null,\"\",\"\"],\"bottom\":[null,\"\",\"\"],\"left\":[null,\"\",\"\"],\"unit\":\"px\"}],\"mobileMarkBorderStyles\":[{\"top\":[null,\"\",\"\"],\"right\":[null,\"\",\"\"],\"bottom\":[null,\"\",\"\"],\"left\":[null,\"\",\"\"],\"unit\":\"px\"}],\"colorClass\":\"theme-palette9\",\"tabletAlign\":\"center\",\"htmlTag\":\"p\"} -->\n<p class=\"kt-adv-heading73_2bc723-2d wp-block-kadence-advancedheading has-theme-palette-9-color has-text-color\" data-kb-block=\"kb-adv-heading73_2bc723-2d\">Use this paragraph section to get your website visitors to know you. Write about you or your organization, the products or services you offer, or why you exist. Keep a consistent communication style. Consider using this if you need to provide more context on why you do what you do. Be engaging. Focus on delivering value to your visitors.</p>\n<!-- /wp:kadence/advancedheading --></div></div>\n<!-- /wp:kadence/column -->\n<!-- /wp:kadence/rowlayout --></div></div>\n<!-- /wp:kadence/column -->\n<!-- /wp:kadence/rowlayout -->','в•ЁРӘв•Ёв•ӣв•Ёв•ңв•ӨР’в•Ёв–‘в•Ёв•‘в•ӨР’в•ӨРӣ','','inherit','closed','closed','','73-revision-v1','','','2026-03-08 14:14:42','2026-03-08 11:14:42','',73,'http://danil.local/?p=76',0,'revision','',0),(77,1,'2026-03-08 14:22:27','2026-03-08 11:22:27','','в•ЁР°в•Ёв–‘в•ӨР‘в•Ёв”җв•Ёв••в•ӨР‘в•Ёв–‘в•Ёв•ңв•Ёв••в•Ёв•Ў','','inherit','closed','closed','','37-revision-v1','','','2026-03-08 14:22:27','2026-03-08 11:22:27','',37,'http://danil.local/?p=77',0,'revision','',0),(79,1,'2026-03-08 14:37:10','2026-03-08 11:37:10','<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>2000в•Ёв”Ӯ</strong>&nbsp;СӮРҗРЈ в•ЁРӘв•Ёв•ӣв•Ёв•ңв•Ёв•‘в•ӨР“в•ӨРҗв•ӨР‘ в•Ёв”җв•ӨРҗв•Ёв•ӣв•Ёв•Ўв•Ёв•‘в•ӨР’в•Ёв•ӣв•Ёв–“ в•Ёв•ңв•Ёв–‘ в•Ёв–“в•Ёв•ӣв•ӨР‘в•ӨР‘в•Ёв•ӣв•Ёв•–в•Ёв”Өв•Ёв–‘в•Ёв•ңв•Ёв••в•Ёв•Ў в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘. в•ЁРҜв•Ёв•ӣв•Ёв–’в•Ёв•Ўв•Ёв”Өв•Ёв••в•ӨР’в•Ёв•Ўв•Ёв•—в•ӨРң в•Ёв•‘в•Ёв•ӣв•Ёв•ңв•Ёв•‘в•ӨР“в•ӨРҗв•ӨР‘в•Ёв–‘ СӮРҗРЈ в•Ёв–‘в•ӨРҗв•ӨР•в•Ёв••в•ӨР’в•Ёв•Ўв•Ёв•‘в•ӨР’в•Ёв•ӣв•ӨРҗ в•ЁРў.в•ЁРІ. в•ЁРЈв•Ёв•ӣв•Ёв•—в•Ёв•ӣв•Ёв–“в•Ёв•Ўв•ӨРҗв•Ёв•ӣв•Ёв–“, в•ЁР®в•ЁР в•ЁР® в”¬Р»в•ЁРӘв•ӨРҗв•Ёв–‘в•ӨР‘в•Ёв•ңв•Ёв•ӣв•Ёв”Өв•Ёв–‘в•ӨРҗв•Ёв”Ӯв•ӨРҗв•Ёв–‘в•Ёв•ўв•Ёв”Өв•Ёв–‘в•Ёв•ңв•Ёв”җв•ӨРҗв•Ёв•ӣв•Ёв•Ўв•Ёв•‘в•ӨР’в”¬в•—</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>17.12.2003в•Ёв”Ӯ</strong>&nbsp; СӮРҗРӨ в•ЁР§в•Ёв–‘в•Ёв•‘в•Ёв•—в•Ёв–‘в•Ёв”Өв•Ёв•‘в•Ёв–‘ в•ЁР¬в•Ёв••в•ӨР’в•ӨРҗв•Ёв•ӣв•Ёв”җв•Ёв•ӣв•Ёв•—в•Ёв••в•ӨР’в•Ёв•ӣв•Ёв•қ в•ЁРҘв•Ёв•‘в•Ёв–‘в•ӨР’в•Ёв•Ўв•ӨРҗв•Ёв••в•Ёв•ңв•Ёв•ӣв•Ёв”Өв•Ёв–‘в•ӨРҗв•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•Ёв•• в•ЁРӘв•ӨР“в•Ёв–’в•Ёв–‘в•Ёв•ңв•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•ЁРЁв•ӨР‘в•Ёв••в•Ёв”Өв•Ёв•ӣв•ӨРҗв•Ёв•ӣв•Ёв•қ в•Ёв–“в•Ёв•ӣв•ӨР‘в•ӨР‘в•Ёв•ӣв•Ёв•–в•Ёв”Өв•Ёв–‘в•Ёв–“в•Ёв–‘в•Ёв•Ўв•Ёв•қв•Ёв•ӣв•Ёв”Ӯв•Ёв•ӣ в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘ .</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>15.06.2005в•Ёв”Ӯ</strong>&nbsp;СӮРҗРЈ в•ЁР®в•ӨР‘в•Ёв–“в•ӨРҹв•ӨРҷв•Ёв•Ўв•Ёв•ңв•Ёв••в•Ёв•Ў в•Ёв•‘в•ӨРҗв•Ёв•Ўв•ӨР‘в•ӨР’в•Ёв•ӣв•Ёв–“ в•Ёв•• в•Ёв•‘в•Ёв•ӣв•Ёв•—в•Ёв•ӣв•Ёв•‘в•Ёв•ӣв•Ёв•—в•Ёв•ӣв•Ёв–“ в•Ёв•ңв•Ёв•ӣв•Ёв–“в•Ёв•ӣв•Ёв”Ӯв•Ёв•ӣ в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘ в•ЁРҜв•Ёв–‘в•ӨР’в•ӨРҗв•Ёв••в•Ёв–‘в•ӨРҗв•ӨР•в•Ёв•ӣв•Ёв•қ в•ЁР¬в•Ёв•ӣв•ӨР‘в•Ёв•‘в•Ёв•ӣв•Ёв–“в•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•Ёв•• в•Ёв–“в•ӨР‘в•Ёв•Ўв•ӨРҹ в•ЁР°в•ӨР“в•ӨР‘в•Ёв•• в•ЁР в•Ёв•—в•Ёв•Ўв•Ёв•‘в•ӨР‘в•Ёв••в•Ёв•Ўв•Ёв•қ II</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>28.05.2006в•Ёв”Ӯ</strong>&nbsp;СӮРҗРЈ в•ЁР®в•ӨР‘в•Ёв–“в•ӨРҹв•ӨРҷв•Ёв•Ўв•Ёв•ңв•Ёв••в•Ёв•Ў в•Ёв–“в•Ёв•ӣв•ӨР‘в•ӨР‘в•Ёв•ӣв•Ёв•–в•Ёв”Өв•Ёв–‘в•Ёв•ңв•Ёв•ңв•Ёв•ӣв•Ёв”Ӯв•Ёв•ӣ в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘ в•ЁР¬в•Ёв••в•ӨР’в•ӨРҗв•Ёв•ӣв•Ёв”җв•Ёв•ӣв•Ёв•—в•Ёв••в•ӨР’в•Ёв•ӣв•Ёв•қ в•ЁРұв•Ёв•қв•Ёв•ӣв•Ёв•—в•Ёв•Ўв•Ёв•ңв•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ&nbsp; в•Ёв•• в•ЁРӘв•Ёв–‘в•Ёв•—в•Ёв••в•Ёв•ңв•Ёв••в•Ёв•ңв•Ёв”Ӯв•ӨРҗв•Ёв–‘в•Ёв”Өв•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•ЁРӘв•Ёв••в•ӨРҗв•Ёв••в•Ёв•—в•Ёв•—в•Ёв•ӣв•Ёв•қ, в•Ёв••в•Ёв•–в•Ёв–’в•ӨРҗв•Ёв–‘в•Ёв•ңв•Ёв•ңв•ӨРӣв•Ёв•қ в•Ёв–“ 2009 в•Ёв”Ӯ в•ЁРҜв•Ёв–‘в•ӨР’в•ӨРҗв•Ёв••в•Ёв–‘в•ӨРҗв•ӨР•в•Ёв•ӣв•Ёв•қ в•ЁР¬в•Ёв•ӣв•ӨР‘в•Ёв•‘в•Ёв•ӣв•Ёв–“в•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•Ёв•• в•Ёв–“в•ӨР‘в•Ёв•Ўв•ӨРҹ в•ЁР°в•ӨР“в•ӨР‘в•Ёв••. в•ЁРӯв•Ёв–‘в•ӨР—в•Ёв–‘в•Ёв•—в•Ёв•ӣ в•Ёв”җв•ӨРҗв•Ёв••в•ӨР•в•Ёв•ӣв•Ёв”Өв•ӨР‘в•Ёв•‘в•Ёв•ӣв•Ёв•Ј в•Ёв”Өв•Ёв•Ўв•ӨРҹв•ӨР’в•Ёв•Ўв•Ёв•—в•ӨРңв•Ёв•ңв•Ёв•ӣв•ӨР‘в•ӨР’в•Ёв••.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"id\":80,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://danil.local/wp-content/uploads/2026/03/letopis.jpg\" alt=\"\" class=\"wp-image-80\"/></figure>\n<!-- /wp:image -->','в•ЁРЁв•ӨР‘в•ӨР’в•Ёв•ӣв•ӨРҗв•Ёв••в•ӨРҹ в•Ёв–“в•Ёв•ӣв•Ёв•–в•ӨРҗв•Ёв•ӣв•Ёв•ўв•Ёв”Өв•Ёв•Ўв•Ёв•ңв•Ёв••в•ӨРҹ в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘ 2000 -2006в•Ёв”Ӯ.в•Ёв”Ӯ.','','publish','closed','closed','','%d0%b8%d1%81%d1%82%d0%be%d1%80%d0%b8%d1%8f-%d0%b2%d0%be%d0%b7%d1%80%d0%be%d0%b6%d0%b4%d0%b5%d0%bd%d0%b8%d1%8f-%d1%81%d0%be%d0%b1%d0%be%d1%80%d0%b0-2000-2006%d0%b3-%d0%b3','','','2026-03-08 15:20:59','2026-03-08 12:20:59','',0,'http://danil.local/?post_type=church_history&#038;p=79',0,'church_history','',0),(80,1,'2026-03-08 14:35:52','2026-03-08 11:35:52','','letopis','','inherit','open','closed','','letopis','','','2026-03-08 14:35:52','2026-03-08 11:35:52','',79,'http://danil.local/wp-content/uploads/2026/03/letopis.jpg',0,'attachment','image/jpeg',0),(81,1,'2026-03-08 14:37:10','2026-03-08 11:37:10','<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>2000в•Ёв”Ӯ</strong>&nbsp;СӮРҗРЈ в•ЁРӘв•Ёв•ӣв•Ёв•ңв•Ёв•‘в•ӨР“в•ӨРҗв•ӨР‘ в•Ёв”җв•ӨРҗв•Ёв•ӣв•Ёв•Ўв•Ёв•‘в•ӨР’в•Ёв•ӣв•Ёв–“ в•Ёв•ңв•Ёв–‘ в•Ёв–“в•Ёв•ӣв•ӨР‘в•ӨР‘в•Ёв•ӣв•Ёв•–в•Ёв”Өв•Ёв–‘в•Ёв•ңв•Ёв••в•Ёв•Ў в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘. в•ЁРҜв•Ёв•ӣв•Ёв–’в•Ёв•Ўв•Ёв”Өв•Ёв••в•ӨР’в•Ёв•Ўв•Ёв•—в•ӨРң в•Ёв•‘в•Ёв•ӣв•Ёв•ңв•Ёв•‘в•ӨР“в•ӨРҗв•ӨР‘в•Ёв–‘ СӮРҗРЈ в•Ёв–‘в•ӨРҗв•ӨР•в•Ёв••в•ӨР’в•Ёв•Ўв•Ёв•‘в•ӨР’в•Ёв•ӣв•ӨРҗ в•ЁРў.в•ЁРІ. в•ЁРЈв•Ёв•ӣв•Ёв•—в•Ёв•ӣв•Ёв–“в•Ёв•Ўв•ӨРҗв•Ёв•ӣв•Ёв–“, в•ЁР®в•ЁР в•ЁР® в”¬Р»в•ЁРӘв•ӨРҗв•Ёв–‘в•ӨР‘в•Ёв•ңв•Ёв•ӣв•Ёв”Өв•Ёв–‘в•ӨРҗв•Ёв”Ӯв•ӨРҗв•Ёв–‘в•Ёв•ўв•Ёв”Өв•Ёв–‘в•Ёв•ңв•Ёв”җв•ӨРҗв•Ёв•ӣв•Ёв•Ўв•Ёв•‘в•ӨР’в”¬в•—</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>17.12.2003в•Ёв”Ӯ</strong>&nbsp; СӮРҗРӨ в•ЁР§в•Ёв–‘в•Ёв•‘в•Ёв•—в•Ёв–‘в•Ёв”Өв•Ёв•‘в•Ёв–‘ в•ЁР¬в•Ёв••в•ӨР’в•ӨРҗв•Ёв•ӣв•Ёв”җв•Ёв•ӣв•Ёв•—в•Ёв••в•ӨР’в•Ёв•ӣв•Ёв•қ в•ЁРҘв•Ёв•‘в•Ёв–‘в•ӨР’в•Ёв•Ўв•ӨРҗв•Ёв••в•Ёв•ңв•Ёв•ӣв•Ёв”Өв•Ёв–‘в•ӨРҗв•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•Ёв•• в•ЁРӘв•ӨР“в•Ёв–’в•Ёв–‘в•Ёв•ңв•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•ЁРЁв•ӨР‘в•Ёв••в•Ёв”Өв•Ёв•ӣв•ӨРҗв•Ёв•ӣв•Ёв•қ в•Ёв–“в•Ёв•ӣв•ӨР‘в•ӨР‘в•Ёв•ӣв•Ёв•–в•Ёв”Өв•Ёв–‘в•Ёв–“в•Ёв–‘в•Ёв•Ўв•Ёв•қв•Ёв•ӣв•Ёв”Ӯв•Ёв•ӣ в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘ .</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>15.06.2005в•Ёв”Ӯ</strong>&nbsp;СӮРҗРЈ в•ЁР®в•ӨР‘в•Ёв–“в•ӨРҹв•ӨРҷв•Ёв•Ўв•Ёв•ңв•Ёв••в•Ёв•Ў в•Ёв•‘в•ӨРҗв•Ёв•Ўв•ӨР‘в•ӨР’в•Ёв•ӣв•Ёв–“ в•Ёв•• в•Ёв•‘в•Ёв•ӣв•Ёв•—в•Ёв•ӣв•Ёв•‘в•Ёв•ӣв•Ёв•—в•Ёв•ӣв•Ёв–“ в•Ёв•ңв•Ёв•ӣв•Ёв–“в•Ёв•ӣв•Ёв”Ӯв•Ёв•ӣ в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘ в•ЁРҜв•Ёв–‘в•ӨР’в•ӨРҗв•Ёв••в•Ёв–‘в•ӨРҗв•ӨР•в•Ёв•ӣв•Ёв•қ в•ЁР¬в•Ёв•ӣв•ӨР‘в•Ёв•‘в•Ёв•ӣв•Ёв–“в•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•Ёв•• в•Ёв–“в•ӨР‘в•Ёв•Ўв•ӨРҹ в•ЁР°в•ӨР“в•ӨР‘в•Ёв•• в•ЁР в•Ёв•—в•Ёв•Ўв•Ёв•‘в•ӨР‘в•Ёв••в•Ёв•Ўв•Ёв•қ II</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\"} -->\n<p class=\"has-text-align-left\"><strong>28.05.2006в•Ёв”Ӯ</strong>&nbsp;СӮРҗРЈ в•ЁР®в•ӨР‘в•Ёв–“в•ӨРҹв•ӨРҷв•Ёв•Ўв•Ёв•ңв•Ёв••в•Ёв•Ў в•Ёв–“в•Ёв•ӣв•ӨР‘в•ӨР‘в•Ёв•ӣв•Ёв•–в•Ёв”Өв•Ёв–‘в•Ёв•ңв•Ёв•ңв•Ёв•ӣв•Ёв”Ӯв•Ёв•ӣ в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘ в•ЁР¬в•Ёв••в•ӨР’в•ӨРҗв•Ёв•ӣв•Ёв”җв•Ёв•ӣв•Ёв•—в•Ёв••в•ӨР’в•Ёв•ӣв•Ёв•қ в•ЁРұв•Ёв•қв•Ёв•ӣв•Ёв•—в•Ёв•Ўв•Ёв•ңв•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ&nbsp; в•Ёв•• в•ЁРӘв•Ёв–‘в•Ёв•—в•Ёв••в•Ёв•ңв•Ёв••в•Ёв•ңв•Ёв”Ӯв•ӨРҗв•Ёв–‘в•Ёв”Өв•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•ЁРӘв•Ёв••в•ӨРҗв•Ёв••в•Ёв•—в•Ёв•—в•Ёв•ӣв•Ёв•қ, в•Ёв••в•Ёв•–в•Ёв–’в•ӨРҗв•Ёв–‘в•Ёв•ңв•Ёв•ңв•ӨРӣв•Ёв•қ в•Ёв–“ 2009 в•Ёв”Ӯ в•ЁРҜв•Ёв–‘в•ӨР’в•ӨРҗв•Ёв••в•Ёв–‘в•ӨРҗв•ӨР•в•Ёв•ӣв•Ёв•қ в•ЁР¬в•Ёв•ӣв•ӨР‘в•Ёв•‘в•Ёв•ӣв•Ёв–“в•ӨР‘в•Ёв•‘в•Ёв••в•Ёв•қ в•Ёв•• в•Ёв–“в•ӨР‘в•Ёв•Ўв•ӨРҹ в•ЁР°в•ӨР“в•ӨР‘в•Ёв••. в•ЁРӯв•Ёв–‘в•ӨР—в•Ёв–‘в•Ёв•—в•Ёв•ӣ в•Ёв”җв•ӨРҗв•Ёв••в•ӨР•в•Ёв•ӣв•Ёв”Өв•ӨР‘в•Ёв•‘в•Ёв•ӣв•Ёв•Ј в•Ёв”Өв•Ёв•Ўв•ӨРҹв•ӨР’в•Ёв•Ўв•Ёв•—в•ӨРңв•Ёв•ңв•Ёв•ӣв•ӨР‘в•ӨР’в•Ёв••.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {\"id\":80,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"http://danil.local/wp-content/uploads/2026/03/letopis.jpg\" alt=\"\" class=\"wp-image-80\"/></figure>\n<!-- /wp:image -->','в•ЁРЁв•ӨР‘в•ӨР’в•Ёв•ӣв•ӨРҗв•Ёв••в•ӨРҹ в•Ёв–“в•Ёв•ӣв•Ёв•–в•ӨРҗв•Ёв•ӣв•Ёв•ўв•Ёв”Өв•Ёв•Ўв•Ёв•ңв•Ёв••в•ӨРҹ в•ӨР‘в•Ёв•ӣв•Ёв–’в•Ёв•ӣв•ӨРҗв•Ёв–‘ 2000 -2006в•Ёв”Ӯ.в•Ёв”Ӯ.','','inherit','closed','closed','','79-revision-v1','','','2026-03-08 14:37:10','2026-03-08 11:37:10','',79,'http://danil.local/?p=81',0,'revision','',0),(94,1,'2026-03-08 17:47:05','2026-03-08 14:47:05','http://danil.local/wp-content/uploads/2026/03/cropped-ukY7RJWKF6iBluOGj2Jg.webp','cropped-ukY7RJWKF6iBluOGj2Jg.webp','','inherit','open','closed','','cropped-uky7rjwkf6ibluogj2jg-webp','','','2026-03-08 17:47:05','2026-03-08 14:47:05','',30,'http://danil.local/wp-content/uploads/2026/03/cropped-ukY7RJWKF6iBluOGj2Jg.webp',0,'attachment','image/webp',0),(100,1,'2026-03-08